SIM_DIR = PROJECT_ROOT / "paper_breadth_aggressive"
STATE_FILE = SIM_DIR / "portfolio_state.json"
SUMMARY_FILE = REPORT_DIR / "breadth_aggressive_paper_latest.json"

PROFILE_NAME = "进取宽度独立盘"
PROFILE_SLUG = "breadth_aggressive"
INITIAL_CASH = 1_000_000
TODAY_STR = datetime.now().strftime("%Y%m%d")
NOW_STR = datetime.now().strftime("%Y-%m-%d %H:%M:%S")


def load_state():
    if STATE_FILE.exists():
        with open(STATE_FILE) as f:
            return json.load(f)
    return {"holdings": {}, "nav_history": [], "cash": INITIAL_CASH}


def load_latest_summary():
    if SUMMARY_FILE.exists():
        with open(SUMMARY_FILE) as f:
            return json.load(f)
    return {}


def load_nav_curve(state=None):
    """加载模拟盘自己的资金历史，不再混用长周期回测曲线。"""
    import pandas as pd

    history_file = REPORT_DIR / "breadth_aggressive_daily_history.csv"
    if history_file.exists():
        try:
            df = pd.read_csv(history_file)
            if len(df) > 0:
                if "generated_at" in df.columns:
                    df["ts"] = pd.to_datetime(df["generated_at"].astype(str).str.split("#").str[0], errors="coerce")
                elif "date" in df.columns:
                    df["ts"] = pd.to_datetime(df["date"], errors="coerce")
                else:
                    df["ts"] = pd.RangeIndex(start=0, stop=len(df), step=1)
                df["equity"] = pd.to_numeric(df.get("total_value"), errors="coerce")
                df["nav"] = pd.to_numeric(df.get("nav"), errors="coerce")
                df["cash"] = pd.to_numeric(df.get("cash"), errors="coerce")
                df = df.dropna(subset=["equity"]).copy()
                if len(df) > 0:
                    return df
        except Exception:
            pass

    nav_history = (state or {}).get("nav_history", []) if isinstance(state, dict) else []
    if nav_history:
        rows = []
        for item in nav_history:
            nav = float(item.get("nav", 0) or 0)
            cash = float(item.get("cash", 0) or 0)
            rows.append({
                "ts": str(item.get("date", "-")),
                "date": str(item.get("date", "-")),
                "equity": round(nav * INITIAL_CASH, 2),
                "nav": nav,
                "cash": cash,
            })
        return pd.DataFrame(rows)
    return None


def get_realtime_prices(symbols):
    prices = {}
    try:
        from run_live_execution_v1 import fetch_realtime_quote
        for sym in symbols:
            quote = fetch_realtime_quote(sym)
            if quote and quote.get("last", 0) > 0:
                prices[sym] = {
                    "price": quote["last"],
                    "pct": quote.get("pct", 0),
                    "name": quote.get("name", ""),
                    "source": quote.get("source", "realtime"),
                }
    except Exception:
        pass
    if len(prices) < len(symbols):
        try:
            import pandas as pd
            pred_path = get_predictions_path("auto", fallback_to_historical=True)
            preds = pd.read_csv(pred_path)
            preds["date"] = pd.to_datetime(preds["date"])
            latest = preds[preds["date"] == preds["date"].max()]
            for sym in symbols:
                if sym in prices:
                    continue
                row = latest[latest["symbol"] == sym]
                if len(row) > 0:
                    prices[sym] = {"price": 1.0, "pct": 0.0, "name": "", "source": "nav"}
        except Exception:
            pass
    return prices


def load_breadth():
    try:
        import run_qlib_breadth_sanity_check as sanity
        b = sanity.load_market_breadth()
        latest = b.index.max()
        return float(b.loc[latest]) if latest in b.index else float(b.iloc[-1])
    except Exception:
        return None


PROFILE = {"low_th": 0.45, "mid_th": 0.55, "low_scale": 0.40, "mid_scale": 0.70, "high_scale": 1.00}
RISK_DEGREE = 0.80


def compute_metrics(state, nav_df, summary=None):
    """计算模拟盘口径绩效指标"""
    holdings = state.get("holdings", {})
    nav_history = state.get("nav_history", [])
    cash = float(state.get("cash", INITIAL_CASH) or 0)
    total_value = cash + sum(float(h.get("current_value", 0) or 0) for h in holdings.values())

    nav = total_value / INITIAL_CASH if INITIAL_CASH > 0 else 1.0
    total_return = (nav - 1.0) * 100

    # 年化：优先按模拟盘自己的历史区间算；如果区间过短，直接回退为累计收益率
    annual_return = total_return
    if nav_df is not None and len(nav_df) >= 2:
        try:
            ts_series = nav_df["ts"] if "ts" in nav_df.columns else None
            d1 = ts_series.iloc[0] if ts_series is not None else None
            d2 = ts_series.iloc[-1] if ts_series is not None else None
            if d1 is not None and d2 is not None and hasattr(d1, 'to_pydatetime'):
                d1 = d1.to_pydatetime()
                d2 = d2.to_pydatetime()
            years = max((d2 - d1).total_seconds() / (365.0 * 24 * 3600), 1 / 365) if d1 is not None and d2 is not None else 0
            if years > 0:
                annual_return = ((nav / 1.0) ** (1 / years) - 1) * 100
        except Exception:
            annual_return = total_return

    # 最大回撤：严格用模拟盘自己的历史
    if nav_df is not None and len(nav_df) > 0 and "nav" in nav_df.columns:
        rolling_max = nav_df["nav"].cummax()
        drawdown = (nav_df["nav"] - rolling_max) / rolling_max * 100
        max_drawdown = float(drawdown.min())
        min_idx = drawdown.idxmin()
        if "date" in nav_df.columns:
            max_dd_date = nav_df.loc[min_idx, "date"]
        else:
            max_dd_date = str(min_idx)
    else:
        max_drawdown = 0.0
        max_dd_date = None

    breadth_val = load_breadth()
    position_scale = (PROFILE["high_scale"] if breadth_val and breadth_val >= PROFILE["mid_th"]
                      else PROFILE["mid_scale"] if breadth_val and breadth_val >= PROFILE["low_th"]
                      else PROFILE["low_scale"])
    target_position = RISK_DEGREE * position_scale
    actual_position_pct = ((total_value - cash) / total_value * 100) if total_value > 0 else 0.0

    summary = summary or {}
    signal_date = str(summary.get("signal_date") or "-")
    if signal_date == "-":
        if nav_df is not None and len(nav_df) > 0 and "date" in nav_df.columns:
            signal_date = str(nav_df.iloc[-1]["date"])
        elif nav_history:
            signal_date = str(nav_history[-1].get("date", "-"))

    return {
        "nav": nav,
        "total_return_pct": total_return,
        "annual_return_pct": annual_return,
        "max_drawdown_pct": max_drawdown,
        "max_dd_date": str(max_dd_date) if max_dd_date else "-",
        "cash": cash,
        "market_value": total_value - cash,
        "total_value": total_value,
        "position_count": len(holdings),
        "target_position_pct": target_position * 100,
        "actual_position_pct": actual_position_pct,
        "breadth": breadth_val,
        "position_scale": position_scale,
        "signal_date": signal_date,
        "signal_stale": bool(summary.get("signal_stale", False)),
        "signal_stale_reason": str(summary.get("signal_stale_reason") or ""),
        "signal_lag_days": summary.get("signal_lag_days"),
        "absolute_lag_days": summary.get("absolute_lag_days"),
        "current_date": str(summary.get("current_date") or "-"),
        "feature_latest_date": str(summary.get("feature_latest_date") or "-"),
        "prediction_source_file": str(summary.get("prediction_source_file") or ""),
        "live_predictions_exist": bool(summary.get("live_predictions_exist", False)),
        "refresh_hint": str(summary.get("refresh_hint") or ""),
        "execution_status": str(summary.get("execution_status") or ""),
    }


