#!/usr/bin/env python3
from __future__ import annotations

import json
from datetime import datetime
from pathlib import Path
from typing import Any

import experiment_registry as experiment_registry_mod


PROJECT_ROOT = Path(__file__).resolve().parents[1]
REPORT_DIR = PROJECT_ROOT / "research" / "reports"
REGISTRY_PATH = PROJECT_ROOT / "config" / "strategy_registry_v2.json"
OWNERS_PATH = PROJECT_ROOT / "config" / "strategy_governance_owners_v1.json"
INCIDENT_TEMPLATE_PATH = PROJECT_ROOT / "docs" / "INCIDENT_TEMPLATE_V1.md"
EXPERIMENT_REGISTRY_PATH = PROJECT_ROOT / "config" / "experiment_registry_v1.json"
RUNTIME_RISK_PATH = REPORT_DIR / "runtime_risk_state_latest.json"
DRAWDOWN_WATCH_STATE_PATH = REPORT_DIR / "strategy_drawdown_watch_state.json"
DRAWDOWN_REVIEW_REPORT_GLOB = "strategy_drawdown_governance_review_*.json"


def load_json(path: Path) -> dict[str, Any]:
    if not path.exists():
        return {}
    return json.loads(path.read_text(encoding="utf-8"))


def path_exists(value: str) -> bool:
    text = str(value or "").strip()
    return bool(text) and Path(text).exists()


def parse_float(value: Any, default: float = 0.0) -> float:
    try:
        return float(str(value).replace(",", "").strip())
    except Exception:
        return default


def validate_registry(
    registry: dict[str, Any],
    owners: dict[str, Any],
    experiment_registry: dict[str, Any],
) -> tuple[list[dict[str, Any]], list[str]]:
    role_map = (owners.get("roles") or {}) if isinstance(owners, dict) else {}
    required_signoffs = ((registry.get("policy") or {}).get("required_signoff_roles") or {}) if isinstance(registry, dict) else {}
    strategies = registry.get("strategies") or []
    experiment_summaries = {
        str(item.get("strategy_id") or ""): item
        for item in (experiment_registry.get("strategy_summaries") or [])
        if str(item.get("strategy_id") or "").strip()
    }

    rows: list[dict[str, Any]] = []
    blocking_issues: list[str] = []
    for item in strategies:
        strategy_id = str(item.get("strategy_id") or "").strip()
        state = str(item.get("state") or "").strip().lower()
        owner_role = str(item.get("owner_role") or "").strip()
        signoffs = [str(x).strip() for x in (item.get("signoffs") or []) if str(x).strip()]
        evidence = item.get("promotion_evidence") or {}
        experiment_summary = experiment_summaries.get(strategy_id) or {}

        issues: list[str] = []
        if not strategy_id:
            issues.append("missing_strategy_id")
        if owner_role not in role_map:
            issues.append("unknown_owner_role")
        if not str(item.get("location") or "").strip():
            issues.append("missing_location")

        if state in {"candidate", "approved"}:
            if not bool(item.get("signal_schema_ready")):
                issues.append("signal_schema_not_ready")
            if not bool(item.get("risk_engine_ready")):
                issues.append("risk_engine_not_ready")
            if not path_exists(str(evidence.get("decision_record") or "")):
                issues.append("missing_decision_record")
            if not experiment_summary:
                issues.append("missing_experiment_registry_summary")
            else:
                missing_experiments = experiment_summary.get("missing_required_experiment_types") or []
                if missing_experiments:
                    issues.append(f"missing_experiments:{'|'.join(str(x) for x in missing_experiments)}")
                latest_promotion_state = str(experiment_summary.get("latest_promotion_state") or "")
                if latest_promotion_state and latest_promotion_state != "none" and not experiment_registry_mod.state_ge(
                    latest_promotion_state,
                    state,
                ):
                    issues.append(f"experiment_state_below_registry:{latest_promotion_state}")
                if not bool(experiment_summary.get("registry_ready")):
                    issues.append("experiment_registry_not_ready")

        if state == "approved":
            if not bool(item.get("live_chain_ready")):
                issues.append("approved_without_live_chain")
            if not path_exists(str(evidence.get("paper_trade_report") or "")):
                issues.append("approved_without_paper_trade_report")

        needed_roles = [str(x).strip() for x in (required_signoffs.get(state) or []) if str(x).strip()]
        missing_signoffs = [role for role in needed_roles if role not in signoffs]
        if missing_signoffs:
            issues.append(f"missing_signoffs:{'|'.join(missing_signoffs)}")

        status = "PASS" if not issues else "BLOCK"
        if issues:
            blocking_issues.append(f"{strategy_id}:{','.join(issues)}")

        rows.append(
            {
                "strategy_id": strategy_id,
                "state": state,
                "owner_role": owner_role,
                "status": status,
                "issues": issues,
            }
        )

    return rows, blocking_issues


def validate_ownership(owners: dict[str, Any]) -> list[str]:
    issues: list[str] = []
    roles = owners.get("roles") or {}
    ownership = owners.get("ownership") or []

    for row in ownership:
        area = str(row.get("area") or "").strip()
        owner_role = str(row.get("owner_role") or "").strip()
        review_role = str(row.get("review_role") or "").strip()
        paths = row.get("paths") or []
        if owner_role not in roles:
            issues.append(f"{area}:unknown_owner_role")
        if review_role not in roles:
            issues.append(f"{area}:unknown_review_role")
        missing_paths = [p for p in paths if not (PROJECT_ROOT / p).exists()]
        if missing_paths:
            issues.append(f"{area}:missing_paths:{'|'.join(missing_paths)}")
    return issues


def load_drawdown_manual_review(runtime_date_tag: str) -> dict[str, Any]:
    normalized = str(runtime_date_tag or "").strip()
    latest_payload: dict[str, Any] = {}
    for path in sorted(REPORT_DIR.glob(DRAWDOWN_REVIEW_REPORT_GLOB), reverse=True):
        payload = load_json(path)
        if payload and not latest_payload:
            payload["_path"] = str(path)
            latest_payload = payload
        if normalized and str(payload.get("runtime_date_tag") or "").strip() == normalized:
            payload["_path"] = str(path)
            return payload
    return latest_payload


def evaluate_drawdown_review(
    registry: dict[str, Any],
    *,
    runtime_payload: dict[str, Any],
    previous_state: dict[str, Any],
) -> tuple[dict[str, Any], dict[str, Any], list[str]]:
    policy = (registry.get("policy") or {}) if isinstance(registry, dict) else {}
    drawdown_policy = (policy.get("drawdown_review") or {}) if isinstance(policy, dict) else {}
    threshold = parse_float(drawdown_policy.get("max_drawdown_threshold_pct"), 10.0)
    required_days = max(1, int(parse_float(drawdown_policy.get("consecutive_days"), 3)))
    runtime_date_tag = str(runtime_payload.get("date_tag") or datetime.now().strftime("%Y%m%d"))
    runtime_metrics = runtime_payload.get("runtime_metrics") or {}
    strategy_max_dd_pct = parse_float(runtime_metrics.get("strategy_max_dd_pct"), 0.0)
    trigger_hit = strategy_max_dd_pct >= threshold

    previous_rows = previous_state.get("strategies") or {}
    strategies = registry.get("strategies") or []
    rows: list[dict[str, Any]] = []
    next_rows: dict[str, Any] = {}
    blocking: list[str] = []

    for item in strategies:
        strategy_id = str(item.get("strategy_id") or "").strip()
        state = str(item.get("state") or "").strip().lower()
        owner_role = str(item.get("owner_role") or "").strip() or "unassigned_owner"
        if not strategy_id:
            continue
        prev = previous_rows.get(strategy_id) or {}
        prev_count = int(prev.get("consecutive_trigger_days") or 0)
        prev_date = str(prev.get("last_evaluated_date_tag") or "")
        if trigger_hit:
            if prev_date == runtime_date_tag:
                consecutive = prev_count
            else:
                consecutive = prev_count + 1
        else:
            consecutive = 0
        review_required = state in {"candidate", "approved"} and trigger_hit and consecutive >= required_days
        conclusion = "pending_manual_decision" if review_required else "monitoring"
        owner_signature = f"{owner_role}:AUTO_SIGNATURE_PENDING"
        row = {
            "strategy_id": strategy_id,
            "registry_state": state,
            "owner_role": owner_role,
            "trigger_hit": trigger_hit,
            "strategy_max_drawdown_pct": round(strategy_max_dd_pct, 4),
            "threshold_pct": threshold,
            "consecutive_trigger_days": consecutive,
            "required_consecutive_days": required_days,
            "review_required": review_required,
            "owner_signature": owner_signature,
            "review_conclusion": conclusion,
            "evaluated_date_tag": runtime_date_tag,
        }
        rows.append(row)
        next_rows[strategy_id] = {
            "last_evaluated_date_tag": runtime_date_tag,
            "consecutive_trigger_days": consecutive,
            "trigger_hit": trigger_hit,
            "review_required": review_required,
            "owner_signature": owner_signature,
            "review_conclusion": conclusion,
        }
