def load_push_state():
    if not PUSH_STATE_FILE.exists():
        return {}
    try:
        return json.loads(PUSH_STATE_FILE.read_text(encoding='utf-8'))
    except Exception:
        return {}


def save_push_state(payload):
    STATE_DIR.mkdir(parents=True, exist_ok=True)
    PUSH_STATE_FILE.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding='utf-8')


def build_signal_fingerprint(signal_type, signals):
    rows = []
    for item in signals:
        rows.append({
            'symbol': item.get('symbol'),
            'action': signal_type,
            'price': round(float(item.get('price', 0) or 0), 2),
            'quantity': int(item.get('quantity', 0) or 0),
            'reason': str(item.get('reason', '')),
        })
    rows = sorted(rows, key=lambda x: (str(x['symbol']), str(x['reason']), x['quantity'], x['price']))
    return json.dumps(rows, ensure_ascii=False, sort_keys=True)


def push_signal_to_feishu(signal_type, signals):
    """推送信号到飞书（同一批信号只推一次）"""
    if not signals:
        return

    fingerprint = build_signal_fingerprint(signal_type, signals)
    state = load_push_state()
    prev = state.get(signal_type) or {}
    if prev.get('fingerprint') == fingerprint:
        print(f"⏭️ {signal_type} 信号与上一批一致，跳过重复推送")
        return

    now = datetime.now().strftime("%Y-%m-%d %H:%M")

