def build_signal_fingerprint(signal_type, signals):
    rows = []
    for item in signals:
        reason = str(item.get('reason', ''))
        reason_key = reason.split(':', 1)[0].strip() if ':' in reason else reason
        rows.append({
            'symbol': item.get('symbol'),
            'action': signal_type,
            'quantity': int(item.get('quantity', 0) or 0),
            'reason_key': reason_key,
        })
    rows = sorted(rows, key=lambda x: (str(x['symbol']), str(x['reason_key']), x['quantity']))
    return json.dumps(rows, ensure_ascii=False, sort_keys=True)

