def load_recent_intraday_buys(max_age_minutes=35):
    today = datetime.now().strftime('%Y%m%d')
    files = sorted(INTRADAY_DIR.glob(f'paper_aggressive_intraday_round*_{today}.json'))
    if not files:
        return []
    latest = files[-1]
    try:
        payload = json.loads(latest.read_text(encoding='utf-8'))
    except Exception:
        return []
    ts = str(payload.get('timestamp') or '').strip()
    if ts:
        try:
            dt = datetime.strptime(ts, '%Y-%m-%d %H:%M:%S')
            age_min = (datetime.now() - dt).total_seconds() / 60.0
            if age_min > max_age_minutes:
                return []
        except Exception:
            pass
    buys = []
    for item in payload.get('buys', []) or []:
        buys.append({
            'symbol': item.get('ts_code'),
            'name': item.get('name'),
            'price': float(item.get('price', 0) or 0),
            'budget': float(item.get('total_cost', item.get('cost', 0)) or 0),
            'reason': str(item.get('reason') or '盘中候选触发买入'),
        })
    return buys

